const inputItems = $input.all();

const knowledgeSections = [];

for (let i = 0; i < inputItems.length; i++) {
  const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');

  const fileName =
    inputItems[i].binary?.data?.fileName ||
    inputItems[i].binary?.data?.fileNameOriginal ||
    `knowledge-file-${i + 1}.md`;

  const fileText = buffer.toString('utf8');

  knowledgeSections.push(
    `\n\n---\nFAJL: ${fileName}\n---\n${fileText}`
  );
}

const chatInput = $('When chat message received').first().json.chatInput;

return [
  {
    json: {
      chatInput,
      knowledgeBase: knowledgeSections.join('\n'),
      loadedFiles: inputItems.length,
      loadedAt: new Date().toISOString()
    }
  }
];

const chatInput = String($json.chatInput || '').trim();
const text = chatInput.toLowerCase();
const chatTriggerData = $('When chat message received').first().json;

const sessionId = String(
  chatTriggerData.sessionId ||
  chatTriggerData.session_id ||
  chatTriggerData.chatSessionId ||
  chatTriggerData.chat_session_id ||
  'unknown-session'
);

function getBelgradeTimestamp() {
  return new Date().toLocaleString('sv-SE', {
    timeZone: 'Europe/Belgrade',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false
  });
}

function extractPhone(input) {
  const matches = [...input.matchAll(/(?:\+381|0)6\d[\s\/.-]?\d{3}[\s\/.-]?\d{3,4}/g)];
  const match = matches[matches.length - 1];
  return match ? match[0].replace(/[\s\/.-]/g, '') : '';
}

function extractEmail(input) {
  const matches = [...input.matchAll(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/gi)];
  const match = matches[matches.length - 1];
  return match ? match[0].toLowerCase() : '';
}

function extractName(input) {
  const patterns = [
    /moje ime je\s+([a-zA-ZčćžšđČĆŽŠĐ\s]+?)(?:,|\.|telefon|broj|$)/i,
    /zovem se\s+([a-zA-ZčćžšđČĆŽŠĐ\s]+?)(?:,|\.|telefon|broj|$)/i,
    /ja sam\s+([a-zA-ZčćžšđČĆŽŠĐ\s]+?)(?:,|\.|telefon|broj|$)/i
  ];

  for (const pattern of patterns) {
    const match = input.match(pattern);
    if (match && match[1]) return match[1].trim();
  }

  return '';
}

function extractLocation(lowerText) {
  if (lowerText.includes('novi beograd') || lowerText.includes('novom beogradu')) return 'Novi Beograd';
  if (lowerText.includes('zemun') || lowerText.includes('zemunu')) return 'Zemun';
  if (lowerText.includes('beograd') || lowerText.includes('beogradu')) return 'Beograd';
  return '';
}

function extractServiceType(lowerText) {
  if (lowerText.includes('generalno') || lowerText.includes('generalnog')) return 'Generalno čišćenje';
  if (lowerText.includes('redovno')) return 'Redovno čišćenje';
  if (lowerText.includes('dubinsko') || lowerText.includes('dubinskog')) return 'Dubinsko pranje';

  if (
    lowerText.includes('poslovni prostor') ||
    lowerText.includes('poslovnog prostora') ||
    lowerText.includes('održavanje poslovnog')
  ) {
    return 'Održavanje poslovnih prostora';
  }

  return '';
}

function extractPropertyType(lowerText) {
  if (lowerText.includes('stan')) return 'Stan';
  if (lowerText.includes('kuća') || lowerText.includes('kuca')) return 'Kuća';
  if (
    lowerText.includes('poslovni prostor') ||
    lowerText.includes('poslovnog prostora') ||
    lowerText.includes('poslovnom prostoru') ||
    lowerText.includes('poslovnim prostorom') ||
    lowerText.includes('kancelarija') ||
    lowerText.includes('kancelarije') ||
    lowerText.includes('kancelariji')
  ) return 'Poslovni prostor';
  if (lowerText.includes('lokal')) return 'Lokal';
  if (lowerText.includes('zgrada')) return 'Zgrada';
  return '';
}

function extractSquareMeters(input) {
  const match = input.match(/(\d+)\s*(m2|m²|kvadrata|kvadratnih|kvm)/i);
  return match ? match[1] : '';
}

function extractDesiredDate(input, lowerText) {
  const explicitDate = input.match(/\b(\d{1,2}[.\/-]\d{1,2}(?:[.\/-]\d{2,4})?)\b/);
  if (explicitDate) return explicitDate[1];
  if (lowerText.includes('danas')) return 'Danas';
  if (lowerText.includes('sutra')) return 'Sutra';
  if (
    lowerText.includes('sledeće nedelje') ||
    lowerText.includes('sledeca nedelja') ||
    lowerText.includes('sledeća nedelja')
  ) return 'Sledeća nedelja';
  if (lowerText.includes('ove nedelje')) return 'Ove nedelje';
  return '';
}

function extractCustomerType(lowerText) {
  if (
    lowerText.includes('firma') ||
    lowerText.includes('firme') ||
    lowerText.includes('firmi') ||
    lowerText.includes('firmu') ||
    lowerText.includes('firmom') ||
    lowerText.includes('pravno lice') ||
    lowerText.includes('kompanija') ||
    lowerText.includes('preduzeće') ||
    lowerText.includes('preduzece')
  ) return 'Pravno lice';
  if (lowerText.includes('fizičko lice') || lowerText.includes('fizicko lice')) return 'Fizičko lice';
  return '';
}

const timestamp = getBelgradeTimestamp();

return [
  {
    json: {
      created_at: timestamp,
      updated_at: timestamp,
      session_id: sessionId,
      source: 'n8n-chat',
      name: extractName(chatInput),
      phone: extractPhone(chatInput),
      email: extractEmail(chatInput),
      location: extractLocation(text),
      service_type: extractServiceType(text),
      property_type: extractPropertyType(text),
      square_meters: extractSquareMeters(chatInput),
      desired_date: extractDesiredDate(chatInput, text),
      customer_type: extractCustomerType(text),
      request_summary: chatInput,
      status: 'new',
      notes: 'Lead se dopunjava kroz razgovor. Potrebna provera operatera.',
      conversation_text: '',
      notification_key: '',
      notification_status: '',
      notification_attempts: 0,
      notification_last_attempt_at: '',
      notification_sent_at: '',
      notification_message_id: '',
      notification_error: ''
    }
  }
];

const newLead = $('Prepare Lead Data').first().json;
const foundRows = $input.all();

let existingLead = {};

if (
  foundRows.length > 0 &&
  foundRows[0].json &&
  foundRows[0].json.session_id &&
  String(foundRows[0].json.session_id) === String(newLead.session_id)
) {
  existingLead = foundRows[0].json;
}

function keepOldOrUseNew(oldValue, newValue) {
  const oldClean = oldValue ? String(oldValue).trim() : '';
  const newClean = newValue ? String(newValue).trim() : '';
  return newClean || oldClean;
}

function appendTurn(history, role, message) {
  const historyClean = history ? String(history).trim() : '';
  const messageClean = message ? String(message).trim() : '';
  if (!messageClean) return historyClean;

  const turn = role + ': ' + messageClean;
  if (!historyClean) return turn;

  const turns = historyClean.split('\n---\n');
  if (turns[turns.length - 1] === turn) return historyClean;

  return historyClean + '\n---\n' + turn;
}

const hasLeadData = [
  newLead.name,
  newLead.phone,
  newLead.email,
  newLead.location,
  newLead.service_type,
  newLead.property_type,
  newLead.square_meters,
  newLead.desired_date,
  newLead.customer_type
].some((value) => String(value || '').trim() !== '');

const mergedLead = {
  created_at: existingLead.created_at || newLead.created_at,
  updated_at: newLead.updated_at,
  session_id: newLead.session_id,
  source: existingLead.source || newLead.source,
  name: keepOldOrUseNew(existingLead.name, newLead.name),
  phone: keepOldOrUseNew(existingLead.phone, newLead.phone),
  email: keepOldOrUseNew(existingLead.email, newLead.email),
  location: keepOldOrUseNew(existingLead.location, newLead.location),
  service_type: keepOldOrUseNew(existingLead.service_type, newLead.service_type),
  property_type: keepOldOrUseNew(existingLead.property_type, newLead.property_type),
  square_meters: keepOldOrUseNew(existingLead.square_meters, newLead.square_meters),
  desired_date: keepOldOrUseNew(existingLead.desired_date, newLead.desired_date),
  customer_type: keepOldOrUseNew(existingLead.customer_type, newLead.customer_type),
  request_summary: newLead.request_summary,
  status: existingLead.status || (hasLeadData ? 'collecting' : 'new'),
  notes: existingLead.notes || newLead.notes,
  conversation_text: appendTurn(existingLead.conversation_text, 'KORISNIK', newLead.request_summary),
  notification_key: keepOldOrUseNew(existingLead.notification_key, newLead.notification_key),
  notification_status: keepOldOrUseNew(existingLead.notification_status, newLead.notification_status),
  notification_attempts: Number(existingLead.notification_attempts || newLead.notification_attempts || 0),
  notification_last_attempt_at: keepOldOrUseNew(existingLead.notification_last_attempt_at, newLead.notification_last_attempt_at),
  notification_sent_at: keepOldOrUseNew(existingLead.notification_sent_at, newLead.notification_sent_at),
  notification_message_id: keepOldOrUseNew(existingLead.notification_message_id, newLead.notification_message_id),
  notification_error: keepOldOrUseNew(existingLead.notification_error, newLead.notification_error)
};

return [{ json: mergedLead }];

const promptItems = $input.all();

const leadState = $('Resolve Operator Handoff').first().json;
const conversationData = $('Code in JavaScript').first().json;

const combinedPrompts = promptItems
  .map((item) => {
    const binaryFile = item.binary?.data;

    if (!binaryFile?.data) {
      return '';
    }

    const fileName = binaryFile.fileName || 'unknown-prompt.md';
    const content = Buffer.from(binaryFile.data, 'base64').toString('utf8');

    return `===== ${fileName} =====\n${content}`;
  })
  .filter((content) => content !== '')
  .join('\n\n');

return [
  {
    json: {
      ...leadState,
      chatInput: conversationData.chatInput || '',
      knowledgeBase: conversationData.knowledgeBase || '',
      promptEngine: combinedPrompts,
      loadedPromptFiles: promptItems.length
    }
  }
];

const leadState = $('Combine Prompt Files').first().json;
const aiResponse = String($json.text || $json.output || '').trim();

if (!aiResponse) {
  throw new Error('AI odgovor je prazan; istorija razgovora nije sačuvana.');
}

function appendTurn(history, role, message) {
  const historyClean = history ? String(history).trim() : '';
  const messageClean = message ? String(message).trim() : '';
  const turn = role + ': ' + messageClean;
  if (!historyClean) return turn;
  return historyClean + '\n---\n' + turn;
}

const updatedAt = new Date().toLocaleString('sv-SE', {
  timeZone: 'Europe/Belgrade',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: false
});

return [
  {
    json: {
      ...leadState,
      updated_at: updatedAt,
      conversation_text: appendTurn(leadState.conversation_text, 'AI', aiResponse),
      text: aiResponse
    }
  }
];

const lead = { ...$json };

function clean(value) {
  return value === null || value === undefined ? '' : String(value).trim();
}

const latestMessage = clean(lead.request_summary).toLowerCase();
const history = clean(lead.conversation_text).toLowerCase();
const context = history + '\n' + latestMessage;

const knownLeadFields = [
  lead.service_type,
  lead.location,
  lead.property_type,
  lead.square_meters,
  lead.desired_date,
  lead.name,
  lead.phone,
  lead.email,
  lead.customer_type
].some((value) => clean(value) !== '');

const collectionIntent = /(?:želim|zelim|treba mi|potrebno mi|zaka(?:z|ž)|termin|ponud|tačn(?:a|u) cen|tacn(?:a|u) cen|koliko košta|koliko kosta|kontakt|pozove|operater|zainteresovan)/i.test(context) || knownLeadFields;
const contactRequested = /(?:kontakt|pozove|operater|javi mi se|javite mi se)/i.test(context);
const priceRequested = /(?:cen|koliko košta|koliko kosta|ponud)/i.test(context);
const service = clean(lead.service_type).toLowerCase();
const isBusiness = service.includes('poslov') || clean(lead.customer_type).toLowerCase().includes('pravno');
const requiresProperty = service.includes('general') || service.includes('redovno') || service.includes('poslov');
const requiresSquareMeters = requiresProperty;
const deepCleaningItemsKnown = /(?:sofa|trosed|fotelj|dušek|dusek|stolic|tepih|nameštaj|namestaj|komad)/i.test(context);

const fieldKnown = {
  service_type: clean(lead.service_type) !== '',
  location: clean(lead.location) !== '',
  property_type: clean(lead.property_type) !== '',
  square_meters: clean(lead.square_meters) !== '',
  desired_date: clean(lead.desired_date) !== '',
  phone: clean(lead.phone) !== '',
  name: clean(lead.name) !== '',
  email: clean(lead.email) !== '',
  customer_type: clean(lead.customer_type) !== '',
  item_details: deepCleaningItemsKnown
};

let priority = [];

if (collectionIntent) {
  if (contactRequested) {
    priority = ['phone', 'name', 'service_type', 'location', 'desired_date'];
  } else {
    priority.push('service_type', 'location');

    if (isBusiness) {
      priority.push('customer_type');
    }

    if (requiresProperty) {
      priority.push('property_type');
    }

    if (requiresSquareMeters) {
      priority.push('square_meters');
    }

    if (service.includes('dubinsko')) {
      priority.push('item_details');
    }

    if (priceRequested) {
      priority.push('phone', 'name', 'desired_date');
    } else {
      priority.push('desired_date', 'phone', 'name');
    }

    if (isBusiness) {
      priority.push('email');
    }
  }
}

const uniquePriority = [...new Set(priority)];
const missingFields = uniquePriority.filter((field) => !fieldKnown[field]);
const nextField = missingFields[0] || '';

const questions = {
  service_type: 'Koja usluga Vam je potrebna?',
  location: 'U kom delu grada se nalazi objekat?',
  property_type: 'O kom tipu objekta je reč?',
  square_meters: 'Kolika je približna kvadratura prostora?',
  desired_date: 'Koji termin Vam okvirno odgovara?',
  phone: 'Koji broj telefona operater može da koristi za kontakt?',
  name: 'Na koje ime da evidentiramo zahtev?',
  email: 'Na koju email adresu želite da primite ponudu?',
  customer_type: 'Da li se javljate kao fizičko ili pravno lice?',
  item_details: 'Šta je potrebno dubinski oprati i koliko komada?'
};

return [
  {
    json: {
      ...lead,
      collection_required: collectionIntent,
      required_fields: uniquePriority,
      missing_fields: missingFields,
      next_field: nextField,
      next_question: nextField ? questions[nextField] : '',
      question_count: nextField ? 1 : 0
    }
  }
];

const lead = { ...$json };

function asUniqueList(value) {
  if (!Array.isArray(value)) return [];
  return [...new Set(value.map((item) => String(item || '').trim()).filter(Boolean))];
}

const requiredFields = asUniqueList(lead.required_fields);
const selectorMissing = new Set(asUniqueList(lead.missing_fields));
const knownRequiredFields = requiredFields.filter((field) => !selectorMissing.has(field));
const missingRequiredFields = requiredFields.filter((field) => selectorMissing.has(field));
const totalRequiredCount = requiredFields.length;
const completedRequiredCount = knownRequiredFields.length;
const completenessApplicable = Boolean(lead.collection_required) && totalRequiredCount > 0;
const completionPercent = completenessApplicable
  ? Math.round((completedRequiredCount / totalRequiredCount) * 100)
  : 0;
const isComplete = completenessApplicable && missingRequiredFields.length === 0;

let status = 'informational';
let notes = 'Informativni upit bez aktivnog prikupljanja lead podataka.';

if (completenessApplicable) {
  status = isComplete ? 'ready_for_operator' : 'collecting';
  notes = isComplete
    ? 'Lead je kompletan po pravilima izabrane usluge i spreman je za operatera.'
    : 'Kompletnost ' + completionPercent + '%. Nedostaju polja: ' + missingRequiredFields.join(', ') + '.';
}

return [
  {
    json: {
      ...lead,
      required_fields: requiredFields,
      known_required_fields: knownRequiredFields,
      missing_required_fields: missingRequiredFields,
      completed_required_count: completedRequiredCount,
      total_required_count: totalRequiredCount,
      completion_percent: completionPercent,
      completeness_applicable: completenessApplicable,
      is_complete: isComplete,
      status,
      notes
    }
  }
];

const lead = { ...$json };

function clean(value) {
  return value === null || value === undefined ? '' : String(value).trim();
}

function valueOrDash(value) {
  return clean(value) || 'Nije prikupljeno';
}

function belgradeTimestamp() {
  return new Date().toLocaleString('sv-SE', {
    timeZone: 'Europe/Belgrade',
    year: 'numeric', month: '2-digit', day: '2-digit',
    hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false
  });
}

const completeLead = lead.is_complete === true && lead.status === 'ready_for_operator';
const previousNotificationStatus = clean(lead.notification_status).toLowerCase();
let operatorSummary = '';
let handoffRequired = false;
let handoffChannel = '';
let notificationSendRequired = false;
let notificationKey = clean(lead.notification_key);
let notificationStatus = previousNotificationStatus;
let notificationAttempts = Number(lead.notification_attempts || 0);
let notificationLastAttemptAt = clean(lead.notification_last_attempt_at);
let notificationSentAt = clean(lead.notification_sent_at);
let notificationMessageId = clean(lead.notification_message_id);
let notificationError = clean(lead.notification_error);
let status = lead.status;
let userCompletionMessage = '';
let notes = lead.notes;

if (completeLead) {
  const lines = [
    'NOVI KOMPLETAN ZAHTEV',
    'Sesija: ' + valueOrDash(lead.session_id),
    'Klijent: ' + valueOrDash(lead.name),
    'Telefon: ' + valueOrDash(lead.phone),
    'Email: ' + valueOrDash(lead.email),
    'Usluga: ' + valueOrDash(lead.service_type),
    'Lokacija: ' + valueOrDash(lead.location),
    'Objekat: ' + valueOrDash(lead.property_type),
    'Kvadratura: ' + valueOrDash(lead.square_meters),
    'Termin: ' + valueOrDash(lead.desired_date),
    'Tip klijenta: ' + valueOrDash(lead.customer_type),
    'Poslednji zahtev: ' + valueOrDash(lead.request_summary),
    'Kompletnost: ' + valueOrDash(lead.completion_percent) + '%'
  ];

  operatorSummary = lines.join('\n');
  handoffRequired = true;
  notificationKey = notificationKey || 'atlas:' + clean(lead.session_id) + ':operator-handoff:v1';
  notes = operatorSummary;

  if (previousNotificationStatus === 'sent') {
    handoffChannel = 'email';
    status = 'handed_off';
    userCompletionMessage = 'Hvala, svi podaci su zabeleženi. Zahtev je već prosleđen operateru emailom i neće biti poslat ponovo.';
  } else if (previousNotificationStatus === 'sending') {
    status = 'handoff_pending';
    userCompletionMessage = 'Hvala, zahtev je sačuvan. Obaveštenje operateru je još u obradi i neću tvrditi da je poslato dok ne dobijemo potvrdu.';
  } else {
    notificationSendRequired = true;
    notificationStatus = 'sending';
    notificationAttempts += 1;
    notificationLastAttemptAt = belgradeTimestamp();
    notificationError = '';
    status = 'handoff_pending';
    userCompletionMessage = 'Hvala, zahtev je sačuvan. Upravo pokušavam da obavestim operatera.';
  }
}

return [{ json: {
  ...lead,
  operator_summary: operatorSummary,
  handoff_required: handoffRequired,
  handoff_channel: handoffChannel,
  notification_send_required: notificationSendRequired,
  notification_key: notificationKey,
  notification_status: notificationStatus,
  notification_attempts: notificationAttempts,
  notification_last_attempt_at: notificationLastAttemptAt,
  notification_sent_at: notificationSentAt,
  notification_message_id: notificationMessageId,
  notification_error: notificationError,
  user_completion_message: userCompletionMessage,
  status,
  notes
} }];

return [{ json: {
  text: 'Trenutno ne mogu pouzdano da proverim informacije firme. Vaš zahtev nije potvrđen. Pokušajte ponovo malo kasnije ili kontaktirajte operatera.',
  failure_code: 'KNOWLEDGE_UNAVAILABLE',
  saved: false
} }];

return [{ json: {
  text: 'Trenutno ne mogu da sačuvam vaš zahtev, zato ga neću označiti kao primljenog. Pokušajte ponovo malo kasnije ili kontaktirajte operatera.',
  failure_code: 'DATA_STORE_UNAVAILABLE',
  saved: false
} }];

return [{ json: {
  text: 'Trenutno ne mogu da obradim poruku. Vaš zahtev nije potvrđen. Pokušajte ponovo malo kasnije ili kontaktirajte operatera.',
  failure_code: 'AI_UNAVAILABLE',
  saved: false
} }];

return [{ json: {
  text: 'Došlo je do privremenog problema i zahtev nije potvrđen. Pokušajte ponovo malo kasnije ili kontaktirajte operatera.',
  failure_code: 'PROCESSING_FAILURE',
  saved: false
} }];

const base = $('Prepare Operator Handoff').first().json;
const result = { ...$json };
const sentAt = new Date().toLocaleString('sv-SE', {
  timeZone: 'Europe/Belgrade',
  year: 'numeric', month: '2-digit', day: '2-digit',
  hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false
});

return [{ json: {
  ...base,
  notification_send_required: false,
  notification_status: 'sent',
  notification_sent_at: sentAt,
  notification_message_id: String(result.messageId || result.message_id || ''),
  notification_error: '',
  handoff_channel: 'email',
  status: 'handed_off'
} }];

const base = $('Prepare Operator Handoff').first().json;
const result = { ...$json };
const rawError = String(result.error?.message || result.error || 'Email server nije potvrdio slanje.');
const safeError = rawError
  .replace(/(?:\+381|0)6\d[\s\/.-]?\d{3}[\s\/.-]?\d{3,4}/g, '[PHONE]')
  .replace(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/gi, '[EMAIL]')
  .slice(0, 500);

return [{ json: {
  ...base,
  notification_send_required: false,
  notification_status: 'failed',
  notification_sent_at: '',
  notification_message_id: '',
  notification_error: safeError,
  handoff_channel: '',
  status: 'notification_failed'
} }];

const base = $('Prepare Operator Handoff').first().json;
const latest = { ...$json };
const lead = { ...base, ...latest };
const notificationStatus = String(lead.notification_status || '').trim().toLowerCase();
const completeLead = base.is_complete === true;
let userCompletionMessage = base.user_completion_message || '';

if (completeLead && notificationStatus === 'sent') {
  userCompletionMessage = 'Hvala, zabeležio sam sve potrebne podatke. Zahtev je uspešno prosleđen operateru emailom, koji će Vas kontaktirati radi potvrde termina i konačnih detalja.';
} else if (completeLead && notificationStatus === 'failed') {
  userCompletionMessage = 'Hvala, Vaš zahtev je sačuvan, ali email obaveštenje operateru trenutno nije poslato. Sistem neće tvrditi da je predaja uspela; neuspešno slanje je evidentirano i može se ponoviti.';
} else if (completeLead && notificationStatus === 'sending') {
  userCompletionMessage = 'Hvala, Vaš zahtev je sačuvan. Status email obaveštenja još nije potvrđen.';
}

return [{ json: {
  ...lead,
  handoff_required: completeLead,
  handoff_channel: notificationStatus === 'sent' ? 'email' : '',
  notification_send_required: false,
  user_completion_message: userCompletionMessage,
  status: notificationStatus === 'sent'
    ? 'handed_off'
    : (completeLead ? (notificationStatus === 'failed' ? 'notification_failed' : 'handoff_pending') : lead.status)
} }];

return [{ json: {
  text: 'Vaš zahtev je sačuvan, ali trenutno ne mogu pouzdano da potvrdim status email obaveštenja. Neću tvrditi da je predaja uspela. Status je ostao označen za proveru operatera.',
  failure_code: 'NOTIFICATION_STATE_UNAVAILABLE',
  saved: true,
  notification_confirmed: false
} }];
